-- PlooTunes E2E baseline seed
--
-- Two parts:
--   1. The GENERATED CATALOG block — canonical artist/album/song rows,
--      produced by the real boot scanner and scraped with e2e/tools/scrape.sql.
--      Replaced wholesale on regeneration; never hand-edited.
--   2. Hand-written fixtures — users, library subscriptions, and an initial
--      queue. These reference songs by PATH via subqueries, never by UUID,
--      so regenerating the catalog (which mints new UUIDs) never invalidates
--      them. See e2e/baseline/README.md for the regeneration workflow.

-- BEGIN GENERATED CATALOG
-- 243 songs generated from e2e/baseline/assets/media by e2e/tools/generateCatalog.mjs
-- Do not hand-edit; regenerate instead. See e2e/baseline/README.md.
-- END GENERATED CATALOG


-- NO trailing slash on folder_path — libraryMembership.ts's half-open range
-- scan (`path >= folder_path || '/' AND path < folder_path || '0'`) depends on it.

SELECT
  '00000000-0000-0000-0000-000000000001',
  ARRAY(SELECT id FROM song WHERE path LIKE '/app/media/Abbath/%' ORDER BY path),
  NULL;

VALUES ('00000000-0000-0000-0000-000000000001', 0, 0, false, 'off');
